// TODO: Create a function that finds a student by name
function findStudent(name) {
  for (let student of students) {
    if (student.name === name) {
      return student;
    }
  }
  return null;  // Not found
}

// TODO: Create a function that updates a student's GPA
function updateGPA(name, newGPA) {
  let student = findStudent(name);
  if (student) {
    student.gpa = newGPA;
    return true;  // Success
  }
  return false;  // Student not found
}

