  { name: "Alice", grade: 10, gpa: 3.8 },
  { name: "Bob", grade: 11, gpa: 3.5 },
  { name: "Charlie", grade: 10, gpa: 3.9 }
];

// Function 1: Display all students
function displayStudents() {
  console.log("=== All Students ===");
  for (let student of students) {
    console.log(student.name + " (Grade " + student.grade + ", GPA " + student.gpa + ")");
  }
}

// Function 2: Add a student
function addStudent(name, grade, gpa) {
  students.push({ name, grade, gpa });
  console.log("Added " + name);
}

// Function 3: Get average GPA
function getAverageGPA() {
  let total = 0;
  for (let student of students) {
    total += student.gpa;
  }
  return (total / students.length).toFixed(2);
}

// Function 4: Find top student by GPA
function getTopStudent() {
  let top = students[0];
  for (let student of students) {
    if (student.gpa > top.gpa) {
      top = student;
    }
  }
  return top;
}

